const DEFAULT_NICHE = 'ai automation';
const rows = $input.all();
const row = rows.find(function (i) { return i.json && i.json.niche; });
const niche = (row && row.json && row.json.niche) || DEFAULT_NICHE;
const kwRaw = (row && row.json && row.json.keywords) || '';
const keywords = kwRaw ? String(kwRaw).split(',').map(function (s) { return s.trim(); }).filter(Boolean) : [];
const seen = new Set();
const terms = [];
const all = [niche].concat(keywords);
for (let i = 0; i < all.length; i++) { const t = all[i]; const k = String(t).toLowerCase(); if (t && !seen.has(k)) { seen.add(k); terms.push(t); } }
const capped = terms.slice(0, 6);
const orQuery = '(' + capped.join(' OR ') + ') lang:en';
return [{ json: { niche: niche, keywords: keywords, terms: capped, orQuery: orQuery } }];

let tk = [], ig = [], yt = [], tw = [];
try { tk = $('TikTok Top').all(); } catch (e) {}
try { ig = $('Instagram Reels').all(); } catch (e) {}
try { yt = $('YouTube').all(); } catch (e) {}
try { tw = $('X Search').all(); } catch (e) {}
const rows = [];
for (let i = 0; i < tk.length; i++) { const o = (tk[i].json && tk[i].json.output) || {}; const arr = (o.data && o.data.items) || o.items || []; for (const v of arr) rows.push({ platform: 'TikTok', author: v.author || '', caption: v.caption || '', url: v.url || '', views: Number(v.views) || 0, likes: Number(v.likes) || 0 }); }
for (let i = 0; i < ig.length; i++) { const o = (ig[i].json && ig[i].json.output) || {}; const arr = (o.data && o.data.reels) || o.reels || []; for (const v of arr) rows.push({ platform: 'Instagram Reels', author: v.username || '', caption: v.caption || '', url: v.url || '', views: Number(v.views) || Number(v.plays) || 0, likes: Number(v.likes) || 0 }); }
for (let i = 0; i < yt.length; i++) { const o = (yt[i].json && yt[i].json.output) || {}; const arr = (o.data && o.data.videos) || o.videos || []; for (const v of arr) rows.push({ platform: 'YouTube', author: v.channel || '', caption: v.title || '', url: v.url || '', views: Number(v.views) || 0, likes: 0 }); }
for (let i = 0; i < tw.length; i++) { const o = (tw[i].json && tw[i].json.output) || {}; const arr = (o.data && o.data.items) || o.items || []; for (const v of arr) rows.push({ platform: 'X', author: (v.author && v.author.userName) || '', caption: v.text || '', url: v.url || v.twitterUrl || '', views: Number(v.viewCount) || 0, likes: Number(v.likeCount) || 0 }); }
const seen = new Set();
const deduped = [];
for (const r of rows) { const k = r.url || (r.platform + r.caption); if (k && !seen.has(k)) { seen.add(k); deduped.push(r); } }
let niche = 'your niche';
try { niche = $('Resolve Niche').first().json.niche || niche; } catch (e) {}
const stems = String(niche).toLowerCase().split(/\s+/).filter(function (w) { return w.length >= 4; }).map(function (w) { return w.slice(0, 5); });
for (const r of deduped) { const hay = (String(r.caption) + ' ' + String(r.author)).toLowerCase(); let rel = 0; for (const s of stems) { if (s && hay.indexOf(s) !== -1) rel++; } r.rel = rel; }
deduped.sort(function (a, b) { if (b.rel !== a.rel) return b.rel - a.rel; return b.views - a.views; });
const top = deduped.slice(0, 30);
const lines = [];
for (let i = 0; i < top.length; i++) { const v = top[i]; lines.push((i + 1) + '. [' + v.platform + '] @' + v.author + ' - ' + (v.views || 0).toLocaleString() + ' views\n   ' + String(v.caption || '').slice(0, 160) + '\n   ' + v.url); }
return [{ json: { niche: niche, generatedAt: $now.toISO(), count: top.length, videos: top, videosText: lines.join('\n\n') } }];

