parameters.text:
=Niche: {{ $('Resolve Niche').item.json.niche }}

Write a short-form video script for the single best idea below (these are the on-niche winners selected for the user):

{{ $('Build Digest').item.json.topText }}

parameters.jsCode:
const brief = ($('Build Digest').first().json.emailBody) || '';
const niche = ($('Build Digest').first().json.niche) || 'your niche';
const script = ($input.first().json.output) || '';
let md = brief + '\n\n---\n\n# Script for the top idea\n\n' + script;
md = md.replace(/\s*[—–]\s*/g, ' - ');
function esc(s) { return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;'); }
function inline(s) {
  s = esc(s);
  s = s.replace(/\[([^\]]+)\]\((https?:[^)\s]+)\)/g, '<a href="$2">$1</a>');
  s = s.replace(/(^|[^"=>])((https?:\/\/)[^\s<]+)/g, '$1<a href="$2">$2</a>');
  s = s.replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>');
  s = s.replace(/\*([^*]+)\*/g, '<em>$1</em>');
  return s;
}
const lines = md.split('\n');
let html = '';
let inList = false;
function closeList() { if (inList) { html += '</ul>'; inList = false; } }
for (let i = 0; i < lines.length; i++) {
  const line = lines[i].trim();
  if (line === '') { closeList(); continue; }
  if (line === '---') { closeList(); html += '<hr>'; continue; }
  if (line.indexOf('## ') === 0) { closeList(); html += '<h2>' + inline(line.slice(3)) + '</h2>'; continue; }
  if (line.indexOf('# ') === 0) { closeList(); html += '<h1>' + inline(line.slice(2)) + '</h1>'; continue; }
  if (line.indexOf('- ') === 0) { if (!inList) { html += '<ul>'; inList = true; } html += '<li>' + inline(line.slice(2)) + '</li>'; continue; }
  closeList();
  html += '<p>' + inline(line) + '</p>';
}
closeList();
const wrapped = '<div style="font-family:-apple-system,Segoe UI,Roboto,Helvetica,Arial,sans-serif;font-size:15px;line-height:1.55;color:#1a1a1a;max-width:640px">' + html + '</div>';
return [{ json: { html: wrapped, niche: niche } }];
